import{_ as a,o as i,c as n,ag as e}from"./chunks/framework.BZohXCq9.js";const c=JSON.parse('{"title":"第17章 RL 训练环境支持","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/17-rl-training.md","filePath":"chapters/17-rl-training.md"}'),t={name:"chapters/17-rl-training.md"};function p(l,s,h,d,r,o){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="第17章-rl-训练环境支持" tabindex="-1">第17章 RL 训练环境支持 <a class="header-anchor" href="#第17章-rl-训练环境支持" aria-label="Permalink to &quot;第17章 RL 训练环境支持&quot;">​</a></h1><blockquote><p>&quot;The key to artificial intelligence has always been the representation.&quot; —— Jeff Hawkins</p></blockquote><p>强化学习（Reinforcement Learning）的核心循环是 Agent 与环境的交互：观察状态、执行动作、获取奖励。这个循环对执行环境有着严格的要求——隔离性、可复现性和资源可控性缺一不可。OpenSandbox 的容器化沙箱恰好满足了这些需求，<code>examples/rl-training/</code> 目录提供了一个完整的 CartPole DQN 训练示例，展示了如何将沙箱作为 RL 训练的基础设施。</p><h2 id="_17-1-rl-训练为什么需要沙箱" tabindex="-1">17.1 RL 训练为什么需要沙箱 <a class="header-anchor" href="#_17-1-rl-训练为什么需要沙箱" aria-label="Permalink to &quot;17.1 RL 训练为什么需要沙箱&quot;">​</a></h2><p>传统 RL 训练通常在本地环境或共享服务器上运行 Gym 环境。这种方式在实验阶段尚可接受，但在规模化训练和生产部署中存在明显问题：</p><ul><li><strong>环境污染</strong>：多个训练实验共享 Python 包和系统状态，一个实验安装的依赖可能影响另一个</li><li><strong>资源争抢</strong>：多个训练进程竞争 CPU 和内存，导致训练速度不稳定，影响结果的可复现性</li><li><strong>安全风险</strong>：RL Agent 可能执行任意代码（尤其在 code-as-action 范式中），缺乏隔离可能危及宿主机</li></ul><p>OpenSandbox 沙箱为每个训练 episode 或训练批次提供独立的容器环境。容器在训练开始时创建，训练结束后销毁，确保每次实验都从干净状态开始。</p><h2 id="_17-2-沙箱作为-rl-环境的映射" tabindex="-1">17.2 沙箱作为 RL 环境的映射 <a class="header-anchor" href="#_17-2-沙箱作为-rl-环境的映射" aria-label="Permalink to &quot;17.2 沙箱作为 RL 环境的映射&quot;">​</a></h2><p>RL 环境的标准接口（如 Gymnasium 的 <code>reset()</code> / <code>step()</code>）可以自然地映射到沙箱操作：</p><table tabindex="0"><thead><tr><th>RL 概念</th><th>沙箱操作</th><th>OpenSandbox API</th></tr></thead><tbody><tr><td><code>reset()</code></td><td>创建新沙箱</td><td><code>POST /sandboxes</code></td></tr><tr><td><code>step(action)</code></td><td>在沙箱中执行命令/代码</td><td>execd <code>POST /command</code> 或 <code>POST /code</code></td></tr><tr><td><code>observe()</code></td><td>读取沙箱状态</td><td>execd <code>GET /files/info</code>、<code>GET /metrics</code></td></tr><tr><td><code>reward()</code></td><td>从执行结果计算奖励</td><td>解析命令输出或文件内容</td></tr><tr><td><code>close()</code></td><td>销毁沙箱</td><td><code>DELETE /sandboxes/{id}</code></td></tr></tbody></table><p>这个映射的关键洞察是：<strong>容器的生命周期与 RL episode 的生命周期对齐</strong>。每个 episode 开始时创建全新的沙箱，结束时销毁。容器的隔离性保证了 episode 之间不存在状态泄露，这是可复现训练的基本前提。</p><h2 id="_17-3-cartpole-dqn-示例解析" tabindex="-1">17.3 CartPole DQN 示例解析 <a class="header-anchor" href="#_17-3-cartpole-dqn-示例解析" aria-label="Permalink to &quot;17.3 CartPole DQN 示例解析&quot;">​</a></h2><p><code>examples/rl-training/</code> 目录包含四个文件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rl-training/</span></span>
<span class="line"><span>├── main.py              # 训练主脚本</span></span>
<span class="line"><span>├── requirements.txt     # 依赖声明</span></span>
<span class="line"><span>├── README.md            # 使用说明</span></span>
<span class="line"><span>└── screenshot.jpg       # 运行效果截图</span></span></code></pre></div><p>训练工作流分为以下步骤：</p><p><strong>第一步：创建沙箱环境</strong>。通过 Python SDK 调用 Lifecycle API 创建一个新的沙箱容器。容器基于 code-interpreter 镜像，预装了 Python 运行时。</p><p><strong>第二步：安装训练依赖</strong>。通过 execd API 在沙箱中执行 <code>pip install</code> 命令，安装 PyTorch、Gymnasium 等 RL 训练所需的库。这一步在沙箱内完成，不会影响宿主机环境。</p><p><strong>第三步：执行训练循环</strong>。将完整的 DQN 训练代码通过 execd 的代码执行 API（<code>POST /code</code>）发送到沙箱中执行。训练过程通过 SSE（Server-Sent Events）实时流式输出日志。</p><p><strong>第四步：收集训练结果</strong>。训练完成后，通过 execd 的文件 API 下载模型检查点和训练报告（JSON 格式）。</p><p>示例支持通过环境变量定制训练参数：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SANDBOX_DOMAIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">localhost:8080</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 服务地址</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SANDBOX_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-key</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 认证密钥</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SANDBOX_IMAGE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">custom-image</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 自定义镜像</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RL_TIMESTEPS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">5000</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 训练步数</span></span></code></pre></div><h2 id="_17-4-资源控制与训练稳定性" tabindex="-1">17.4 资源控制与训练稳定性 <a class="header-anchor" href="#_17-4-资源控制与训练稳定性" aria-label="Permalink to &quot;17.4 资源控制与训练稳定性&quot;">​</a></h2><p>RL 训练对资源的可预测性要求很高。如果训练过程中 CPU 时间被其他进程抢占，同样的超参数在不同运行中可能产生不同的结果。OpenSandbox 提供了多维度的资源控制：</p><p><strong>CPU 和内存限制</strong>：通过 <code>CreateSandboxRequest</code> 中的 resource limits 字段，可以为每个训练沙箱指定精确的 CPU 核数（nano_cpus）和内存上限（mem_limit）。在 Docker 后端，这些参数直接映射到 cgroup 限制；在 Kubernetes 后端，映射到 Pod 的 resources.limits。</p><p><strong>PID 限制</strong>：<code>DockerConfig</code> 中的 <code>pids_limit</code>（默认 512）防止训练代码意外 fork 过多进程。这在使用多进程并行环境（如 SubprocVecEnv）时尤为重要——如果进程数超出限制，系统会明确报错而非静默降级。</p><p><strong>超时控制</strong>：<code>server/src/config.py</code> 中的 <code>max_sandbox_timeout</code> 和 <code>CreateSandboxRequest</code> 中的 <code>expires_at</code> 字段为每个训练沙箱设置最大存活时间。训练超时后沙箱自动销毁，防止失控的训练进程无限期占用资源。</p><h2 id="_17-5-实时监控训练过程" tabindex="-1">17.5 实时监控训练过程 <a class="header-anchor" href="#_17-5-实时监控训练过程" aria-label="Permalink to &quot;17.5 实时监控训练过程&quot;">​</a></h2><p>execd 组件提供了两个监控端点，对 RL 训练过程的可观测性至关重要：</p><ul><li><strong><code>GET /metrics</code></strong>：返回当前时刻的资源使用快照，包括 <code>cpu_cores</code>（核心数）、<code>cpu_usage</code>（使用率，float）、<code>memory_mib</code>（内存使用量）和 <code>timestamp</code>（毫秒级时间戳）</li><li><strong><code>GET /metrics/watch</code></strong>：通过 SSE 实时推送资源指标流</li></ul><p>训练框架可以利用这些指标检测异常状态：如果内存使用持续增长接近上限，可能存在内存泄漏；如果 CPU 使用率骤降为零，训练可能已经死锁。这种实时监控能力使得训练问题的定位从&quot;事后分析日志&quot;变为&quot;实时发现异常&quot;。</p><h2 id="_17-6-批量并行训练" tabindex="-1">17.6 批量并行训练 <a class="header-anchor" href="#_17-6-批量并行训练" aria-label="Permalink to &quot;17.6 批量并行训练&quot;">​</a></h2><p>RL 研究中常常需要用不同随机种子或不同超参数运行多次实验来评估算法的稳定性。BatchSandbox CRD 天然支持这种场景：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sandbox.opensandbox.io/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">BatchSandbox</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  replicas</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  poolRef</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">rl-training-pool</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  taskTemplate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      processTask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        command</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;python&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        args</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/workspace/train.py&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3600</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  shardTaskPatches</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        processTask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          env</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">RANDOM_SEED</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">              value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        processTask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          env</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">RANDOM_SEED</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">              value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # ... 每个分片使用不同的随机种子</span></span></code></pre></div><p>通过 ShardTaskPatches，每个训练副本可以接收不同的随机种子或超参数。BatchSandbox Status 中的 TaskSucceed 和 TaskFailed 计数器让研究者一眼看到有多少训练成功完成。结合 Pool CRD 的预热机制，10 个训练副本可以几乎同时启动，而不必等待镜像拉取。</p><h2 id="_17-7-为什么沙箱适合-rl-训练" tabindex="-1">17.7 为什么沙箱适合 RL 训练 <a class="header-anchor" href="#_17-7-为什么沙箱适合-rl-训练" aria-label="Permalink to &quot;17.7 为什么沙箱适合 RL 训练&quot;">​</a></h2><p>总结 OpenSandbox 在 RL 训练场景中的设计优势：</p><p><strong>隔离性映射 episode 独立性</strong>：容器的生命周期天然对应 episode 的生命周期，无需在应用层实现环境重置逻辑。</p><p><strong>可复现性源于确定性环境</strong>：相同的镜像 + 相同的资源限制 + 相同的随机种子 = 相同的训练轨迹。</p><p><strong>安全性应对任意代码执行</strong>：在 code-as-action 范式中，Agent 生成的代码在沙箱内执行，即使产生危险操作也不会影响宿主机。安全配置（dropped capabilities、AppArmor、Seccomp）提供了多层防护。</p><p><strong>弹性扩展匹配训练规模</strong>：从单个实验到数百个并行训练，只需调整 Replicas 数量和 Pool 容量。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>OpenSandbox 为 RL 训练提供了从单实验到规模化训练的完整支持。容器生命周期与 RL episode 的自然映射消除了环境管理的复杂性，资源限制保证了训练的可复现性，execd 的实时监控使得训练过程透明可观测。<code>examples/rl-training/</code> 中的 CartPole DQN 示例展示了这套方案的实际用法，而 BatchSandbox CRD 将其扩展到了大规模并行训练场景。理解沙箱与 RL 环境之间的映射关系，是在 OpenSandbox 上构建高效训练流水线的第一步。</p>`,42)])])}const E=a(t,[["render",p]]);export{c as __pageData,E as default};
